/// SSH remote worker support for Symphony.
///
/// Constructs SSH subprocess arguments, handles `host:port` parsing
/// (including `user@host:port`, bracketed IPv6 `[::1]:2222`),
/// shell-escapes the remote command, and optionally injects
/// `SYMPHONY_SSH_CONFIG` via `-F`.
///
/// Mirrors the Elixir `SymphonyElixir.SSH` module behavior.
use tokio::process::Child;

/// Host selection result from the orchestrator pool.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum WorkerHostSelection {
    /// No `ssh_hosts` configured — use local subprocess.
    Local,
    /// A remote host was selected.
    Remote(String),
    /// All configured hosts are at capacity.
    NoneAvailable,
}

/// Parse `host`, `host:port`, `user@host:port`, or bracketed IPv6 `[::1]:2222`
/// into `(destination, port)`.
///
/// Returns `(destination, 22)` when no port is present or when the
/// destination part would be invalid (e.g. unbracketed IPv6).
pub fn parse_target(target: &str) -> (String, u16) {
    let trimmed = target.trim();

    // Try to split on the last `:digits` suffix.
    if let Some((left, right)) = rsplit_once_port(trimmed) {
        if valid_port_destination(left) {
            return (left.to_string(), right);
        }
    }

    (trimmed.to_string(), 22)
}

/// Split `s` on the last `:` where the right-hand side is a decimal port
/// number. Returns `(left, port)` or `None`.
fn rsplit_once_port(s: &str) -> Option<(&str, u16)> {
    let colon_pos = s.rfind(':')?;
    let right = &s[colon_pos + 1..];
    let port: u16 = right.parse().ok()?;
    Some((&s[..colon_pos], port))
}

/// A destination is valid for port splitting when:
/// - It is non-empty, AND
/// - It does not contain `:` (plain hostname / IPv4), OR
/// - It is a bracketed IPv6 literal (contains both `[` and `]`).
fn valid_port_destination(destination: &str) -> bool {
    if destination.is_empty() {
        return false;
    }
    if !destination.contains(':') {
        return true;
    }
    // Allow bracketed IPv6 like `[::1]`
    destination.contains('[') && destination.contains(']')
}

/// POSIX single-quote shell escaping.
///
/// Wraps `s` in single quotes, replacing any embedded `'` with `'"'"'`.
/// This matches the Elixir `shell_escape/1` implementation exactly.
pub fn shell_escape(s: &str) -> String {
    format!("'{}'", s.replace('\'', "'\"'\"'"))
}

/// Build the SSH argument list for invoking `command` on `host`.
///
/// The argument list is suitable for passing to `tokio::process::Command`.
/// If the `SYMPHONY_SSH_CONFIG` environment variable is set and non-empty,
/// `-F <path>` is prepended.
pub fn ssh_args(host: &str, command: &str) -> Vec<String> {
    let (destination, port) = parse_target(host);
    let remote_cmd = format!("bash -lc {}", shell_escape(command));

    let mut args: Vec<String> = Vec::new();

    // Inject SSH config if configured.
    if let Ok(cfg) = std::env::var("SYMPHONY_SSH_CONFIG") {
        if !cfg.is_empty() {
            args.push("-F".to_string());
            args.push(cfg);
        }
    }

    args.push("-T".to_string());

    if port != 22 {
        args.push("-p".to_string());
        args.push(port.to_string());
    }

    args.push(destination);
    args.push(remote_cmd);

    args
}

/// Validate that a remote workspace path is absolute (non-empty, starts with `/`).
///
/// Remote paths cannot be canonicalized on the local filesystem; we only
/// verify the minimal structural requirement that the spec mandates.
pub fn validate_remote_workspace_cwd(workspace: &str) -> crate::error::Result<String> {
    if workspace.is_empty() || !workspace.starts_with('/') {
        return Err(crate::error::SymphonyError::InvalidWorkspaceCwd(format!(
            "remote workspace path must be absolute, got: {:?}",
            workspace
        )));
    }
    Ok(workspace.to_string())
}

/// Thin wrapper for launching SSH subprocesses.
pub struct SshRunner;

impl SshRunner {
    /// Spawn an SSH subprocess that runs `command` on `host`.
    ///
    /// Looks up the `ssh` executable on `PATH` and constructs arguments via
    /// [`ssh_args`]. Returns the child process handle.
    pub async fn start_process(host: &str, command: &str) -> crate::error::Result<Child> {
        todo!()
    }
}

